const loginForm=document.getElementById("login-form"),loginError=document.getElementById("login-error");loginForm&&(loginForm.onsubmit=async function(o){o.preventDefault(),loginError.textContent="";const t=new FormData(this),e=t.get("email"),n=t.get("password");try{const o=await fetch("https://alexokoriengobe.onrender.com/api/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:e,password:n})}),t=await o.json();o.ok&&t.token?(localStorage.setItem("token",t.token),window.location.href="index.html"):loginError.textContent=t.message||"Login failed"}catch(o){loginError.textContent="Network error. Please try again."}});